def calculate_tax(income, status):
    if income <= 0:
        return 0.0
    tax = 0.0
    if status == "single":
        if income <= 10000:
            tax = income * 0.1
        elif income <= 40000:
            tax = 1000 + (income - 10000) * 0.15
        else:
            tax = 5500 + (income - 40000) * 0.25
    elif status == "married":
        if income <= 20000:
            tax = income * 0.1
        elif income <= 80000:
            tax = 2000 + (income - 20000) * 0.15
        else:
            tax = 11000 + (income - 80000) * 0.25
    else:
        tax = income * 0.2
    return tax
